using System.Text;
using Microsoft.CodeAnalysis;
using Mockolate.SourceGenerators.Entities;
using Mockolate.SourceGenerators.Internals;
using Type = Mockolate.SourceGenerators.Entities.Type;

namespace Mockolate.SourceGenerators.Sources;

#pragma warning disable S3776 // Cognitive Complexity of methods should not be too high
internal static partial class Sources
{
	private static StringBuilder InitializeBuilder()
	{
		StringBuilder sb = new();
		sb.AppendLine("""
		              //----------------------
		              // <auto-generated>
		              //     This code was generated by the Mockolate source generator.
		              //
		              //     Changes to this file may cause incorrect behavior and
		              //     will be lost if the code is regenerated!
		              // </auto-generated>
		              //----------------------
		              """);

		sb.AppendLine();
		return sb;
	}

	/// <summary>
	///     Generates a comma-separated list of generic type parameters (e.g., "T1, T2, T3").
	/// </summary>
	private static string GetGenericTypeParameters(int count, int startIndex = 1)
		=> string.Join(", ", Enumerable.Range(startIndex, count).Select(i => $"T{i}"));

	/// <summary>
	///     Generates a comma-separated list of generic type parameters with 'out' variance (e.g., "out T1, out T2").
	/// </summary>
	private static string GetOutGenericTypeParameters(int count, int startIndex = 1)
		=> string.Join(", ", Enumerable.Range(startIndex, count).Select(i => $"out T{i}"));

	/// <summary>
	///     Generates a descriptive text listing type parameters (e.g., "T1, T2 and T3" or just "T1").
	/// </summary>
	private static string GetTypeParametersDescription(int numberOfParameters, int startIndex = 1)
	{
		StringBuilder sb = new();
		for (int i = startIndex; i < startIndex + numberOfParameters - 1; i++)
		{
			if (i > startIndex)
			{
				sb.Append(", ");
			}

			sb.Append("<typeparamref name=\"T").Append(i).Append("\" />");
		}

		sb.Append(" and <typeparamref name=\"T").Append(startIndex + numberOfParameters - 1).Append("\" />");
		return sb.ToString();
	}

	/// <summary>
	///     Appends a TriggerCallbacks invocation.
	/// </summary>
	private static void AppendTriggerCallbacks(StringBuilder sb, string indent, string varName,
		IEnumerable<MethodParameter> parameters)
		=> sb.Append(indent).Append(varName).Append("?.TriggerCallbacks(")
			.Append(string.Join(", ", parameters.Select(p => p.ToNameOrWrapper())))
			.Append(");").AppendLine();

	/// <summary>
	///     Formats method parameters with ref/out keywords and names for method invocations.
	/// </summary>
	private static string FormatMethodParametersWithRefKind(IEnumerable<MethodParameter> parameters)
		=> string.Join(", ", parameters.Select(p => $"{p.RefKind.GetString(true)}{p.Name}"));

	/// <summary>
	///     Appends a typed parameter list for indexer accesses, e.g. <c>T1, T2</c>.
	/// </summary>
	private static void AppendIndexerParameterTypes(StringBuilder sb,
		EquatableArray<MethodParameter> parameters)
	{
		bool first = true;
		foreach (MethodParameter p in parameters)
		{
			if (!first)
			{
				sb.Append(", ");
			}

			sb.AppendTypeOrWrapper(p.Type);
			first = false;
		}
	}

	/// <summary>
	///     Appends a constructor-argument list of the form
	///     <c>"p1", p1, "p2", p2</c>.
	/// </summary>
	private static void AppendIndexerParameterArguments(StringBuilder sb,
		EquatableArray<MethodParameter> parameters)
	{
		bool first = true;
		foreach (MethodParameter p in parameters)
		{
			if (!first)
			{
				sb.Append(", ");
			}

			sb.Append('"').Append(p.Name).Append("\", ").Append(p.ToNameOrWrapper());
			first = false;
		}
	}

	/// <summary>
	///     Emits variable declarations for the indexer getter access and matching setup:
	///     <code>var access = new IndexerGetterAccess&lt;T...&gt;("p", p, ...);
	///     mockRegistry.RegisterInteraction(access);
	///     var setup = mockRegistry.GetIndexerSetup&lt;IndexerSetup&lt;TValue, T...&gt;&gt;(access);</code>
	/// </summary>
	private static void EmitIndexerGetterAccessAndSetup(StringBuilder sb, string indent,
		string mockRegistry, string accessVarName, string setupVarName,
		Type propertyType, EquatableArray<MethodParameter> parameters)
	{
		sb.Append(indent).Append("global::Mockolate.Interactions.IndexerGetterAccess<");
		AppendIndexerParameterTypes(sb, parameters);
		sb.Append("> ").Append(accessVarName).Append(" = new(");
		AppendIndexerParameterArguments(sb, parameters);
		sb.Append(");").AppendLine();

		sb.Append(indent).Append("if (").Append(mockRegistry).Append(".Behavior.SkipInteractionRecording == false)").AppendLine();
		sb.Append(indent).Append("{").AppendLine();
		sb.Append(indent).Append('\t').Append(mockRegistry).Append(".RegisterInteraction(").Append(accessVarName).Append(");")
			.AppendLine();
		sb.Append(indent).Append("}").AppendLine();

		sb.Append(indent).Append("global::Mockolate.Setup.IndexerSetup<").AppendTypeOrWrapper(propertyType);
		foreach (MethodParameter p in parameters)
		{
			sb.Append(", ").AppendTypeOrWrapper(p.Type);
		}

		sb.Append(">? ").Append(setupVarName).Append(" = ").Append(mockRegistry)
			.Append(".GetIndexerSetup<global::Mockolate.Setup.IndexerSetup<").AppendTypeOrWrapper(propertyType);
		foreach (MethodParameter p in parameters)
		{
			sb.Append(", ").AppendTypeOrWrapper(p.Type);
		}

		sb.Append(">>(").Append(accessVarName).Append(");").AppendLine();
	}

	/// <summary>
	///     Emits variable declarations for the indexer setter access and matching setup.
	/// </summary>
	private static void EmitIndexerSetterAccessAndSetup(StringBuilder sb, string indent,
		string mockRegistry, string accessVarName, string setupVarName,
		Type propertyType, EquatableArray<MethodParameter> parameters)
	{
		sb.Append(indent).Append("global::Mockolate.Interactions.IndexerSetterAccess<");
		AppendIndexerParameterTypes(sb, parameters);
		sb.Append(", ").AppendTypeOrWrapper(propertyType).Append("> ").Append(accessVarName).Append(" = new(");
		AppendIndexerParameterArguments(sb, parameters);
		sb.Append(", value);").AppendLine();

		sb.Append(indent).Append("if (").Append(mockRegistry).Append(".Behavior.SkipInteractionRecording == false)").AppendLine();
		sb.Append(indent).Append("{").AppendLine();
		sb.Append(indent).Append('\t').Append(mockRegistry).Append(".RegisterInteraction(").Append(accessVarName).Append(");")
			.AppendLine();
		sb.Append(indent).Append("}").AppendLine();

		sb.Append(indent).Append("global::Mockolate.Setup.IndexerSetup<").AppendTypeOrWrapper(propertyType);
		foreach (MethodParameter p in parameters)
		{
			sb.Append(", ").AppendTypeOrWrapper(p.Type);
		}

		sb.Append(">? ").Append(setupVarName).Append(" = ").Append(mockRegistry)
			.Append(".GetIndexerSetup<global::Mockolate.Setup.IndexerSetup<").AppendTypeOrWrapper(propertyType);
		foreach (MethodParameter p in parameters)
		{
			sb.Append(", ").AppendTypeOrWrapper(p.Type);
		}

		sb.Append(">>(").Append(accessVarName).Append(");").AppendLine();
	}

	/// <summary>
	///     Formats indexer parameters as comma-separated names.
	/// </summary>
	private static string FormatIndexerParametersAsNames(EquatableArray<MethodParameter> parameters)
		=> string.Join(", ", parameters.Select(p => p.Name));

	/// <summary>
	///     Formats parameters with type and name (e.g., "int value, string name").
	/// </summary>
	private static string FormatParametersWithTypeAndName(IEnumerable<MethodParameter> parameters)
		=> string.Join(", ", parameters.Select(p => $"{p.Type.Fullname} {p.Name}"));

	/// <summary>
	///     Formats parameters as names only (e.g., "value1, value2").
	/// </summary>
	private static string FormatParametersAsNames(IEnumerable<MethodParameter> parameters)
		=> string.Join(", ", parameters.Select(p => p.Name));

	/// <summary>
	///     Appends a NamedParameter with nullable handling.
	/// </summary>
	private static void AppendNamedParameter(StringBuilder sb, MethodParameter parameter)
	{
		bool useCovarianceAdapter = parameter.RefKind == RefKind.None;
		if (useCovarianceAdapter)
		{
			// Setup parameter is IParameter<T> (or nullable) — use CovariantParameterAdapter to support covariant
			// widening (e.g. passing an IParameter<Derived> where IParameter<Base> is expected).
			sb.Append("CovariantParameterAdapter<");
			sb.AppendTypeOrWrapper(parameter.Type);
			sb.Append(">.Wrap(");
		}
		else
		{
			// out/ref setup parameters use IOutParameter<T> / IRefParameter<T>, which don't inherit from
			// IParameter<T> — covariance isn't applicable, so keep the direct IParameterMatch<T> cast.
			sb.Append("(global::Mockolate.Parameters.IParameterMatch<");
			sb.AppendTypeOrWrapper(parameter.Type);
			sb.Append(">)(");
		}

		sb.Append(parameter.Name);
		if (parameter.CanUseNullableParameterOverload())
		{
			if (parameter.HasExplicitDefaultValue)
			{
				sb.Append(" ?? global::Mockolate.It.Is<").Append(parameter.ToNullableType()).Append(">(")
					.Append(parameter.ExplicitDefaultValue).Append(")");
			}
			else
			{
				sb.Append(" ?? global::Mockolate.It.IsNull<").Append(parameter.ToNullableType()).Append(">(\"null\")");
			}
		}

		sb.Append(")");
	}

	/// <summary>
	///     Appends a NamedParameter wrapping an explicit value with <c>It.Is&lt;T&gt;</c>.
	/// </summary>
	private static void AppendNamedValueParameter(StringBuilder sb, MethodParameter parameter)
		=> AppendNamedValueParameter(sb, parameter, parameter.Name);

	/// <summary>
	///     Appends a NamedParameter wrapping an explicit value with <c>It.Is&lt;T&gt;</c>, using the given variable reference
	///     name.
	/// </summary>
	private static void AppendNamedValueParameter(StringBuilder sb, MethodParameter parameter, string paramRef)
	{
		sb.Append("(global::Mockolate.Parameters.IParameterMatch<");
		sb.AppendTypeOrWrapper(parameter.Type);
		sb.Append(">)global::Mockolate.It.Is<")
			.Append(parameter.ToNullableType()).Append(">(").Append(paramRef).Append(", ");
		if (parameter.Type.SpecialType == SpecialType.System_String)
		{
			sb.Append("$\"\\\"{").Append(paramRef).Append("}\\\"\"");
		}
		else if (parameter.Type.CanBeNullable)
		{
			sb.Append(paramRef).Append(" is null ? \"null\" : ");
			if (parameter.Type.IsFormattable)
			{
				sb.Append("((global::System.IFormattable)").Append(paramRef).Append(").ToString(null, global::System.Globalization.CultureInfo.InvariantCulture)");
			}
			else
			{
				sb.Append(paramRef).Append(".ToString()");
			}
		}
		else if (parameter.Type.IsFormattable)
		{
			sb.Append("((global::System.IFormattable)").Append(paramRef)
				.Append(").ToString(null, global::System.Globalization.CultureInfo.InvariantCulture)");
		}
		else
		{
			sb.Append(paramRef).Append(".ToString()");
		}

		sb.Append(")");
	}

	private static string CreateUniqueParameterName(EquatableArray<MethodParameter> parameters, string name)
	{
		string usedName = name;
#pragma warning disable S1994
		for (int index = 1; parameters.Any(x => x.Name == usedName); index++)
		{
			usedName = $"{usedName}_{index}";
		}
#pragma warning restore S1994

		return usedName;
	}

	private static string CreateUniquePropertyName(Class @class, string initialValue)
	{
		string propertyName = initialValue;
		if (@class.Properties.Any(m => m.Name == propertyName))
		{
			propertyName = $"Mockolate_{initialValue}";
		}

		if (@class.Properties.Any(m => m.Name == propertyName))
		{
			int index = 1;
			do
			{
				propertyName = $"Mockolate_{initialValue}__" + index++;
			} while (@class.Properties.Any(m => m.Name == propertyName));
		}

		return propertyName;
	}

	extension(Accessibility accessibility)
	{
		internal string ToVisibilityString()
			=> accessibility switch
			{
				Accessibility.Protected => "protected",
				Accessibility.Internal => "internal",
				Accessibility.ProtectedOrInternal => "protected",
				Accessibility.Public => "public",
				Accessibility.ProtectedAndInternal => "private protected",
				_ => "private",
			};
	}

	extension(RefKind refKind)
	{
		internal string GetString(bool replaceRefReadonlyWithIn = false)
			=> refKind switch
			{
				RefKind.In => "in ",
				RefKind.Out => "out ",
				RefKind.Ref => "ref ",
				RefKind.RefReadOnlyParameter => replaceRefReadonlyWithIn ? "in " : "ref readonly ",
				_ => "",
			};
	}

	extension(string value)
	{
		private string EscapeForXmlDoc()
			=> value.Replace('<', '{').Replace('>', '}');
	}

	extension(StringBuilder sb)
	{
		/// <summary>
		///     Appends XML documentation summary tags with the given text.
		/// </summary>
		private void AppendXmlSummary(string summaryText, string indent = "\t\t")
		{
			sb.Append(indent).Append("/// <summary>").AppendLine();
			sb.Append(indent).Append("///     ").Append(summaryText).AppendLine();
			sb.Append(indent).Append("/// </summary>").AppendLine();
		}

		/// <summary>
		///     Appends XML documentation remarks tags with the given text.
		/// </summary>
		private void AppendXmlRemarks(string remarksText, string indent = "\t\t")
		{
			sb.Append(indent).Append("/// <remarks>").AppendLine();
			sb.Append(indent).Append("///     ").Append(remarksText).AppendLine();
			sb.Append(indent).Append("/// </remarks>").AppendLine();
		}

		/// <summary>
		///     Appends an XML documentation <c>&lt;remarks&gt;</c> block consisting of several pre-formatted lines.
		/// </summary>
		private void AppendXmlRemarks(string[] lines, string indent = "\t\t")
		{
			if (lines.Length == 0)
			{
				return;
			}

			sb.Append(indent).Append("/// <remarks>").AppendLine();
			for (int i = 0; i < lines.Length; i++)
			{
				sb.Append(indent).Append("///     ").Append(lines[i]);
				if (i < lines.Length - 1)
				{
					sb.Append("<br />");
				}
				sb.AppendLine();
			}
			sb.Append(indent).Append("/// </remarks>").AppendLine();
		}

		/// <summary>
		///     Appends an XML documentation <c>&lt;param&gt;</c> tag with the given name and description.
		/// </summary>
		private void AppendXmlParam(string name, string description, string indent = "\t\t")
			=> sb.Append(indent).Append("/// <param name=\"").Append(name).Append("\">")
				.Append(description).Append("</param>").AppendLine();

		/// <summary>
		///     Appends an XML documentation <c>&lt;typeparam&gt;</c> tag with the given name and description.
		/// </summary>
		private void AppendXmlTypeParam(string name, string description, string indent = "\t\t")
			=> sb.Append(indent).Append("/// <typeparam name=\"").Append(name).Append("\">")
				.Append(description).Append("</typeparam>").AppendLine();

		/// <summary>
		///     Appends an XML documentation <c>&lt;returns&gt;</c> tag with the given text.
		/// </summary>
		private void AppendXmlReturns(string returnsText, string indent = "\t\t")
			=> sb.Append(indent).Append("/// <returns>").Append(returnsText).Append("</returns>").AppendLine();

		/// <summary>
		///     Appends an XML documentation <c>&lt;exception&gt;</c> tag with the given <paramref name="cref" /> and text.
		/// </summary>
		private void AppendXmlException(string cref, string text, string indent = "\t\t")
			=> sb.Append(indent).Append("/// <exception cref=\"").Append(cref).Append("\">")
				.Append(text).Append("</exception>").AppendLine();
	}
}
#pragma warning restore S3776 // Cognitive Complexity of methods should not be too high
